INSERT INTO public.ai_prompts (prompt_type, model_type, prompt_template)
VALUES ('style-analysis', 'technical', 'Проанализируй визуальный стиль этого изображения товарной карточки для маркетплейса. Опиши в 3-5 предложениях: цветовую палитру (основные и акцентные цвета), стиль фона (градиент, текстура, однотонный), типографику (стиль шрифтов, размеры, расположение текста), композицию (расположение товара, пропорции, отступы), графические элементы (иконки, рамки, декоративные элементы, тени). Ответ должен быть кратким техническим описанием стиля, которое можно использовать как инструкцию для создания карточек в таком же стиле.');